import React, { useState } from 'react';

export function PlanTrip() {
  // State for Destination, From, Days, and Travel Date
  const [destination, setDestination] = useState('');
  const [from, setFrom] = useState('');
  const [days, setDays] = useState('');
  const [travelDate, setTravelDate] = useState('');
  
  // Handle change for Destination input
  const handleDestinationChange = (event) => {
    setDestination(event.target.value);
  };

  // Handle change for From input
  const handleFromChange = (event) => {
    setFrom(event.target.value);
  };

  // Handle change for Days input
  const handleDaysChange = (event) => {
    const value = event.target.value;

    // Ensure only numbers are entered
    if (/^\d*$/.test(value)) {
      setDays(value);
    }
  };

  // Handle change for Travel Date input
  const handleTravelDateChange = (event) => {
    setTravelDate(event.target.value);
  };

  // Function to generate and save the user data
 
  const [userData , setUserData] = useState({
    destination,
    from,
    days,
    travelDate,
    });

  function changeHandler(event) {
    setUserData([
      (prev) => [
        {
          ...prev,
          [event.target.name]: event.target.value,
        },
      ],
    ]);

    console.log(" user Data is:-",userData);
  }

  function submitHandler(e) {
    e.preventDefault();

    
    toast.success("trip is planned");
    const userData = {
      ...userData,
    };
    console.log(userData);

    // navigate("/planTrip");
  }


  return (
    <div className="py-8 w-11/12 mx-auto text-white bg-gray-800 rounded-lg shadow-md">
      {/* Heading */}
      <h1 className="text-3xl font-bold text-center mb-6">Enter Trip Details</h1>

      {/* Input for Destination */}
      <div className="flex flex-col py-4 text-white">
        <label className="mb-2 font-semibold">Going to:</label>
        <input
          type="text"
          value={destination}
          onChange={handleDestinationChange, changeHandler}
          onChange={changeHandler}
          placeholder="Destination to..."
          required
          className="px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      {/* Input for From */}
      <div className="flex flex-col py-4 text-white">
        <label className="mb-2 font-semibold">Going from:</label>
        <input
          type="text"
          value={from}
          onChange={handleFromChange}
          placeholder="From..."
          required
          className="px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      {/* Number of Days and Travel Date Inputs */}
      <div className="flex flex-col py-6 my-4">
        <label className="mb-2 font-semibold">Enter no. of days:</label>
        <input
          type="text"
          value={days}
          onChange={handleDaysChange}
          placeholder="Enter number of days"
          className="px-4 py-2 bg-gray-700 text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
        />

        <label className="my-4 mb-2 font-semibold">Enter Date of travel:</label>
        <input
          className="text-black px-4 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          type="date"
          value={travelDate}
          onChange={handleTravelDateChange}
        />
      </div>

      {/* Generate Trip Plan Button */}
      <button
        onClick={generateTripPlan}
        className="bg-blue-500 text-white py-2 px-6 rounded-lg mt-6 hover:bg-blue-600 focus:outline-none focus:ring-2 focus:ring-blue-500"
      >
        Generate Trip Plan
      </button>

      {/* You can optionally use the saved userData for further processing, or keep it hidden */}
      {/* The userData will not be shown on the UI, but is stored and can be used elsewhere */}
    </div>
  );
}
